import{c as n,a7 as i,y as o,B as a,v as e,D as r}from"./chunks/framework.3cjvm90C.js";const _=JSON.parse('{"title":"Transformer 注意力机制：MHA、MQA 与 GQA 的深度对比","description":"深入对比 Multi-Head Attention、Multi-Query Attention 和 Grouped-Query Attention 三种注意力机制的原理与性能差异","frontmatter":{"title":"Transformer 注意力机制：MHA、MQA 与 GQA 的深度对比","description":"深入对比 Multi-Head Attention、Multi-Query Attention 和 Grouped-Query Attention 三种注意力机制的原理与性能差异"},"headers":[],"relativePath":"aigc/pretrain/attention.md","filePath":"aigc/pretrain/attention.md","lastUpdated":1782456021000}'),h={name:"aigc/pretrain/attention.md"};function d(l,t,s,m,$,f){return i(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="transformer-注意力机制-mha、mqa-与-gqa-的深度对比" tabindex="-1">Transformer 注意力机制：MHA、MQA 与 GQA 的深度对比 <a class="header-anchor" href="#transformer-注意力机制-mha、mqa-与-gqa-的深度对比" aria-label="Permalink to “Transformer 注意力机制：MHA、MQA 与 GQA 的深度对比”">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to “背景”">​</a></h2><p>Transformer (<a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">Vaswani et al., 2017</a>) 架构的提出彻底改变了自然语言处理（NLP）领域。该架构最初基于编码器-解码器（Encoder-Decoder）结构，随后演化出一系列变体：如仅包含编码器的 BERT (<a href="https://arxiv.org/abs/1810.04805" target="_blank" rel="noreferrer">Devlin et al., 2018</a>)，以及仅包含解码器的 GPT (<a href="https://cdn.openai.com/research-covers/language-unsupervised/language_understanding_paper.pdf" target="_blank" rel="noreferrer">Radford et al., 2018</a>) 系列。目前主流的大型语言模型（LLM），如 LLaMA (<a href="https://arxiv.org/abs/2302.13971" target="_blank" rel="noreferrer">Touvron et al., 2023</a>) 和 GPT-4，大多延续了<strong>仅解码器（Decoder-only）</strong>的架构。</p><h2 id="符号定义" tabindex="-1">符号定义 <a class="header-anchor" href="#符号定义" aria-label="Permalink to “符号定义”">​</a></h2><table tabindex="0"><thead><tr><th><strong>符号</strong></th><th><strong>含义</strong></th></tr></thead><tbody><tr><td>$B$</td><td>批量大小（Batch Size）</td></tr><tr><td>$S$</td><td>序列长度（Sequence Length）</td></tr><tr><td>$d$</td><td>隐藏层维度 / 模型维度（Model Dimension）</td></tr><tr><td>$H$</td><td>注意力头数量（Number of Attention Heads）</td></tr><tr><td>$G$</td><td>分组数量（Group Number），用于 GQA</td></tr><tr><td>$d_{\\text{head}}$</td><td>每个注意力头的维度，通常 $d_{\\text{head}} = d / H$</td></tr><tr><td>$\\mathbf{X}$</td><td>输入张量，$\\mathbf{X} \\in \\mathbb{R}^{B \\times S \\times d}$</td></tr><tr><td>$\\mathbf{Q}, \\mathbf{K}, \\mathbf{V}$</td><td>经过线性变换后的查询（Query）、键（Key）、值（Value）矩阵</td></tr><tr><td>$W_Q, W_K, W_V$</td><td>映射矩阵，$W \\in \\mathbb{R}^{d \\times d}$，用于生成 $\\mathbf{Q}, \\mathbf{K}, \\mathbf{V}$</td></tr><tr><td>$W_O$</td><td>输出映射矩阵，$W_O \\in \\mathbb{R}^{d \\times d}$</td></tr><tr><td>$\\mathbf{Q}_h, \\mathbf{K}_h, \\mathbf{V}_h$</td><td>第 $h$ 个注意力头对应的子矩阵</td></tr><tr><td>$\\mathbf{K}^<em>, \\mathbf{V}^</em>$</td><td>MQA 中所有头共享的键和值矩阵</td></tr></tbody></table><h2 id="transformer-中的注意力机制" tabindex="-1">Transformer 中的注意力机制 <a class="header-anchor" href="#transformer-中的注意力机制" aria-label="Permalink to “Transformer 中的注意力机制”">​</a></h2><p>Transformer 的核心在于<strong>自注意力机制（Self-Attention）</strong>，它赋予了模型动态捕捉序列内部长程依赖的能力。</p><p>对于输入序列 $\\mathbf{X} \\in \\mathbb{R}^{B \\times S \\times d}$，模型通过可训练的权重矩阵 $W_Q, W_K, W_V \\in \\mathbb{R}^{d \\times d}$ 将其投影到三个子空间： $$ \\mathbf{Q} = \\mathbf{X} W_Q, \\quad \\mathbf{K} = \\mathbf{X} W_K, \\quad \\mathbf{V} = \\mathbf{X} W_V $$ Transformer 采用的是<strong>缩放点积注意力（Scaled Dot-Product Attention）</strong>。其基本思想是计算查询与键之间的相关性，并将其作为权重对值进行加权求和： $$ \\text{Attention}(\\mathbf{Q}, \\mathbf{K}, \\mathbf{V}) = \\text{softmax}\\left(\\frac{\\mathbf{Q} \\mathbf{K}^\\top}{\\sqrt{d_{\\text{head}}}}\\right)\\mathbf{V} $$</p><h3 id="_1-多头注意力-multi-head-attention-mha" tabindex="-1">1. 多头注意力（Multi-Head Attention, MHA） <a class="header-anchor" href="#_1-多头注意力-multi-head-attention-mha" aria-label="Permalink to “1. 多头注意力（Multi-Head Attention, MHA）”">​</a></h3><p>MHA 通过将 $\\mathbf{Q}, \\mathbf{K}, \\mathbf{V}$ 划分为 $H$ 个独立的头，允许模型在不同的表示子空间中并行学习信息： $$ \\text{MHA}(\\mathbf{Q}, \\mathbf{K}, \\mathbf{V}) = \\text{Concat}(\\text{head}_1, \\dots, \\text{head}_H) W_O $$ 其中每个头的计算公式为： $$ \\text{head}_h = \\text{Attention}(\\mathbf{Q}_h, \\mathbf{K}_h, \\mathbf{V}_h) = \\text{softmax}\\left(\\frac{\\mathbf{Q}_h \\mathbf{K}<em>h^\\top}{\\sqrt{d</em>{\\text{head}}}}\\right)\\mathbf{V}_h $$ <strong>MHA 的优势：</strong></p><ul><li><strong>多维度特征捕捉</strong>：不同头可以关注序列中不同的语法或语义特征。</li><li><strong>增强表达能力</strong>：通过子空间集成，提升了模型对复杂依赖关系的建模精度。</li><li><strong>计算并行性</strong>：各头的计算逻辑相互独立，适合 GPU/TPU 硬件加速。</li></ul><h4 id="缩放因子-sqrt-d-text-head-的必要性" tabindex="-1">缩放因子 $\\sqrt{d_{\\text{head}}}$ 的必要性 <a class="header-anchor" href="#缩放因子-sqrt-d-text-head-的必要性" aria-label="Permalink to “缩放因子 $\\sqrt{d_{\\text{head}}}$ 的必要性”">​</a></h4><p>引入缩放因子的主要目的是<strong>维持数值稳定性</strong>，防止 Softmax 函数进入梯度饱和区：</p><ol><li><p><strong>防止梯度消失</strong>：若点积结果过大，Softmax 的输出会集中在极小或极大的区域，导致导数接近于 0。</p></li><li><p><strong>数学推导</strong>：假设 $\\mathbf{q}$ 和 $\\mathbf{k}$ 的各分量是独立同分布的随机变量，且满足均值为 0、方差为 1。则其点积 $\\mathbf{q} \\cdot \\mathbf{k} = \\sum_{i=1}^{d_{\\text{head}}} q_i k_i$ 的方差为 $d_{\\text{head}}$。</p><ul><li>通过除以 $\\sqrt{d_{\\text{head}}}$，可以使缩放后点积的方差恢复为 1： $$ \\text{Var}\\left(\\frac{\\mathbf{q} \\cdot \\mathbf{k}}{\\sqrt{d_{\\text{head}}}}\\right) = \\frac{1}{d_{\\text{head}}} \\text{Var}(\\mathbf{q} \\cdot \\mathbf{k}) = \\frac{d_{\\text{head}}}{d_{\\text{head}}} = 1 $$</li></ul></li></ol><h3 id="_2-多查询注意力-multi-query-attention-mqa" tabindex="-1">2. 多查询注意力（Multi-Query Attention, MQA） <a class="header-anchor" href="#_2-多查询注意力-multi-query-attention-mqa" aria-label="Permalink to “2. 多查询注意力（Multi-Query Attention, MQA）”">​</a></h3><p>MQA (<a href="https://arxiv.org/abs/1911.02150" target="_blank" rel="noreferrer">Shazeer, 2019</a>) 是一种旨在提升推理效率的变体。在 MQA 中，所有的查询头共享同一组键（Key）和值（Value）。</p>',16),e("p",null,[r("其核心逻辑如下： $$ \\mathbf{K}^* = \\text{Linear}"),e("em",{shared:""},"{shared}(\\mathbf{X}), \\quad \\mathbf{V}^* = \\text{Linear}"),r("(\\mathbf{X}) $$")],-1),a('<p>$$ \\text{MQA}(\\mathbf{Q}, \\mathbf{K}^<em>, \\mathbf{V}^</em>) = \\text{Concat}(\\text{Attention}(\\mathbf{Q}_1, \\mathbf{K}^<em>, \\mathbf{V}^</em>), \\dots, \\text{Attention}(\\mathbf{Q}_H, \\mathbf{K}^<em>, \\mathbf{V}^</em>)) W_O $$</p><p><strong>核心价值</strong>：显著减少了推理阶段 <strong>KV Cache</strong> 的显存占用和访存开销（Memory Bandwidth），这对长文本生成尤为重要。</p><h3 id="_3-分组查询注意力-grouped-query-attention-gqa" tabindex="-1">3. 分组查询注意力（Grouped-Query Attention, GQA） <a class="header-anchor" href="#_3-分组查询注意力-grouped-query-attention-gqa" aria-label="Permalink to “3. 分组查询注意力（Grouped-Query Attention, GQA）”">​</a></h3><p>GQA (<a href="https://arxiv.org/pdf/2305.13245" target="_blank" rel="noreferrer">Ainslie, 2023</a>) 是 MHA 与 MQA 的折中方案，它在保持推理效率的同时，尽可能保留多头机制的表达能力。</p><p>GQA 将查询头分为 $G$ 组，每组内的查询头共享一对 KV 头：</p><ul><li>若 $G=1$，则等同于 MQA。</li><li>若 $G=H$，则等同于 MHA。</li></ul><h3 id="三者对比总结" tabindex="-1">三者对比总结 <a class="header-anchor" href="#三者对比总结" aria-label="Permalink to “三者对比总结”">​</a></h3><ul><li><strong>MHA</strong>：$H$ 个 Query 头，$H$ 个 KV 头。性能最优，但推理时 KV Cache 显存压力大。</li><li><strong>MQA</strong>：$H$ 个 Query 头，$1$ 个 KV 头。推理速度最快，显存占用最低，但可能损失一定的模型容量。</li><li><strong>GQA</strong>：$H$ 个 Query 头，$G$ 个 KV 头（$1 &lt; G &lt; H$）。在速度与性能之间取得最佳平衡，是目前主流大模型（如 Llama 3）的首选。</li></ul><h2 id="复杂度分析" tabindex="-1">复杂度分析 <a class="header-anchor" href="#复杂度分析" aria-label="Permalink to “复杂度分析”">​</a></h2><h3 id="_1-时间复杂度-time-complexity" tabindex="-1">1. 时间复杂度（Time Complexity） <a class="header-anchor" href="#_1-时间复杂度-time-complexity" aria-label="Permalink to “1. 时间复杂度（Time Complexity）”">​</a></h3><p>无论是 MHA、MQA 还是 GQA，对于<strong>完整序列的一次性前向传播</strong>，其计算复杂度量级是相同的。</p><ul><li><strong>矩阵乘法 $\\mathbf{Q}\\mathbf{K}^\\top$</strong>：复杂度为 $\\mathcal{O}(B \\times S^2 \\times d)$。</li><li><strong>加权求和（与 $\\mathbf{V}$ 相乘）</strong>：复杂度同样为 $\\mathcal{O}(B \\times S^2 \\times d)$。</li><li><strong>总体量级</strong>：$\\mathcal{O}(B \\times S^2 \\times d)$。注意，注意力机制的计算开销随序列长度 $S$ 呈二次方增长。</li></ul><p>增量解码（Incremental Decoding）场景：</p><p>在 LLM 推理时，利用 KV Cache 缓存历史信息。每生成一个新 Token，只需计算当前 Query 与历史 KV 的关联：</p><ul><li><strong>单步复杂度</strong>：$\\mathcal{O}(B \\times H \\times S_{\\text{past}} \\times d_{\\text{head}}) = \\mathcal{O}(B \\times S_{\\text{past}} \\times d)$。</li></ul><h3 id="_2-空间复杂度-space-complexity" tabindex="-1">2. 空间复杂度（Space Complexity） <a class="header-anchor" href="#_2-空间复杂度-space-complexity" aria-label="Permalink to “2. 空间复杂度（Space Complexity）”">​</a></h3><p>空间复杂度主要由<strong>参数量</strong>和<strong>中间激活值（KV Cache）</strong>组成。</p><ul><li><strong>参数量</strong>：$W_Q, W_K, W_V, W_O$ 四个矩阵的参数量均为 $\\mathcal{O}(d^2)$，总参数量约为 $4d^2$。MQA/GQA 虽然减少了 KV 头的数量，但由于投影矩阵的维度变化，其参数量微减，通常仍视为 $\\mathcal{O}(d^2)$。</li><li><strong>KV Cache 显存占用</strong>：这是 MQA/GQA 优化的核心。 <ul><li><strong>MHA</strong>：每个 Token 需要存储 $2 \\times H \\times d_{\\text{head}} = 2d$ 个数值。</li><li><strong>MQA</strong>：每个 Token 仅需存储 $2 \\times 1 \\times d_{\\text{head}} = 2d/H$ 个数值。显存占用降低为原来的 $1/H$。</li><li><strong>GQA</strong>：每个 Token 需要存储 $2 \\times G \\times d_{\\text{head}}$ 个数值。显存占用介于两者之间。</li></ul></li></ul><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to “结论”">​</a></h2><p>在大语言模型时代，显存带宽往往是推理性能的瓶颈（Memory-Bound）。<strong>MQA</strong> 通过极致的共享策略解决了访存效率问题，但可能影响复杂任务的表现；<strong>GQA</strong> 则通过灵活的分组机制，在推理延迟、显存占用与模型效果之间找到了黄金平衡点，已成为当前工业界的事实标准。</p>',20)])])}const g=n(h,[["render",d]]);export{_ as __pageData,g as default};
